selector_to_html = {"a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.2.2 </span>Screen Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The screen control interface provides full display control capabilities, including emoji playback, video playback, and more. It enables developers to implement rich visual interaction features for the robot.</strong></p>", "a[href=\"../../example/Python.html#py-play-emoji\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.19 </span>Emoji (expression) control<a class=\"headerlink\" href=\"#py-play-emoji\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_emoji</strong>, which enables the robot to display a specified expression. Users can select expressions from the available list. For the full expression list, refer to the <a class=\"reference internal\" href=\"../../Interface/interactor/screen.html#tbl-emotion-id\"><span class=\"std std-ref\">expression list</span></a></p>", "a[href=\"#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Emoji Playback Status Topic<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#playvideo-notes\"]": "<p id=\"playvideo-notes\"><strong>Notes:</strong></p>", "a[href=\"#id6\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Programming Examples<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h2><p>For detailed code examples and explanations, refer to:</p>", "a[href=\"#id4\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Emoji Playback Service<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id5\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Video Playback Service<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"../../example/Cpp.html#cpp-play-emoji\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.19 </span>Emoji Control<a class=\"headerlink\" href=\"#cpp-play-emoji\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_emoji</strong>, which allows the robot to display a specified emoji. Users can choose an emoji from the available list; see the <a class=\"reference internal\" href=\"../../Interface/interactor/screen.html#tbl-emotion-id\"><span class=\"std std-ref\">Emoji List</span></a> for details.</p>", "a[href=\"../../example/Cpp.html#cpp-play-video\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.15 </span>Play Video<a class=\"headerlink\" href=\"#cpp-play-video\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_video.</strong> Before running the node, you must upload the video file to the robot\u2019s <strong>Interaction Computing Unit (PC3)</strong> (you may create a directory there to store videos, e.g. /var/tmp/videos/). Then, modify the <code class=\"docutils literal notranslate\"><span class=\"pre\">video_path</span></code> in the node program to the path of the video you want to play.</p>", "a[href=\"../../example/Python.html#py-play-video\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.15 </span>Play video<a class=\"headerlink\" href=\"#py-play-video\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_video</strong>. Before running the node, you must upload the video to the robot\u2019s <strong>Interaction Computing Unit (PC3)</strong> (you may create a directory on it to store videos, e.g. /var/tmp/videos/), and then change the <code class=\"docutils literal notranslate\"><span class=\"pre\">video_path</span></code> in the node program to the path of the video you want to play.</p>", "a[href=\"#id7\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Safety Notes<a class=\"headerlink\" href=\"#id7\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Key Features<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
